.mb-2 { margin-bottom: 20px; }
.pb-2 { padding-bottom: 20px; }

/* =============================================
   Megapage – hostazar.com
   ============================================= */

/* ---- Breadcrumbs ---- */
.breadcrumbs {
  display: flex;
  align-items: center;
  gap: 6px;
  font-size: 0.85rem;
  color: var(--text-muted);
  margin-bottom: 16px;
  flex-wrap: wrap;
}
.breadcrumbs a { color: var(--text-muted); }
.breadcrumbs a:hover { color: var(--accent); }
.breadcrumbs .sep { color: var(--border); font-size: 1.1rem; }
.breadcrumbs .current { color: var(--text-secondary); }

/* ---- Search Bar ---- */
.search-section {
  max-width: 600px;
  margin: 0 auto 30px;
  position: relative;
}
.search-bar {
  display: flex;
  align-items: center;
  background: var(--bg-card);
  border: 1px solid var(--border);
  border-radius: 30px;
  padding: 4px 4px 4px 20px;
  transition: border-color .2s;
}
.search-bar:focus-within { border-color: var(--accent); }
.search-bar input {
  flex: 1;
  background: none;
  border: none;
  outline: none;
  color: var(--text-primary);
  font-size: 1rem;
  padding: 10px 0;
  font-family: var(--font);
}
.search-bar input::placeholder { color: var(--text-muted); }
.search-reset-btn {
  padding: 8px 18px;
  background: var(--accent);
  color: #fff;
  border: none;
  border-radius: 20px;
  font-size: 0.85rem;
  cursor: pointer;
  font-family: var(--font);
  font-weight: 600;
  transition: background .2s;
}
.search-reset-btn:hover { background: var(--accent-hover); }

/* ---- Category Hero ---- */
.cat-hero {
  background: linear-gradient(135deg, #111 0%, #1a0a1e 50%, #111 100%);
  padding: 60px 0 40px;
  text-align: center;
  border-bottom: 1px solid var(--border);
}
.cat-hero h1 { font-size: 2.4rem; font-weight: 800; margin-bottom: 10px; }
.cat-hero p { font-size: 1.1rem; color: var(--text-secondary); max-width: 600px; margin: 0 auto; }

/* ---- Category Pills (Filter) ---- */
.cat-filter-pills {
  display: flex;
  justify-content: center;
  gap: 8px;
  flex-wrap: wrap;
  padding: 20px 0;
}
.cat-pill, .tag-pill {
  display: inline-block;
  padding: 6px 16px;
  border-radius: 20px;
  background: var(--bg-card);
  color: var(--text-secondary);
  font-size: 0.85rem;
  font-weight: 500;
  border: 1px solid var(--border);
  cursor: pointer;
  transition: all .2s;
  text-decoration: none;
  white-space: nowrap;
}
.cat-pill:hover, .tag-pill:hover { border-color: var(--accent); color: var(--text-primary); }
.cat-pill.active {
  background: var(--accent-dim);
  color: var(--accent-hover);
  border-color: var(--accent);
}
.tag-pill.active {
  background: var(--accent-dim);
  color: var(--accent-hover);
  border-color: var(--accent);
}

/* ---- Tag Cloud ---- */
.tag-cloud {
  display: flex;
  justify-content: center;
  gap: 6px;
  flex-wrap: wrap;
  padding: 0 0 20px;
}
.tag-pill[data-count] { font-size: 0.8rem; }

/* ---- Result Count ---- */
.result-count {
  display: block;
  text-align: center;
  font-size: 0.9rem;
  color: var(--text-muted);
  padding: 10px 0 0;
}

/* ---- Pagination ---- */
.pagination {
  display: flex;
  justify-content: center;
  align-items: center;
  gap: 4px;
  padding: 30px 0 50px;
  flex-wrap: wrap;
}
.page-btn {
  display: inline-flex;
