{"content": "   428|  margin-bottom: 16px;
   429|  flex-wrap: wrap;
   430|}
   431|.breadcrumbs a { color: var(--text-muted); }
   432|.breadcrumbs a:hover { color: var(--accent); }
   433|.breadcrumbs .sep { color: var(--border); font-size: 1.1rem; }
   434|.breadcrumbs .current { color: var(--text-secondary); }
   435|
   436|/* ---- Search Bar ---- */
   437|.search-section {
   438|  max-width: 600px;
   439|  margin: 0 auto 30px;
   440|  position: relative;
   441|}
   442|.search-bar {
   443|  display: flex;
   444|  align-items: center;
   445|  background: var(--bg-card);
   446|  border: 1px solid var(--border);
   447|  border-radius: 30px;
   448|  padding: 4px 4px 4px 20px;
   449|  transition: border-color .2s;
   450|}
   451|.search-bar:focus-within { border-color: var(--accent); }
   452|.search-bar input {
   453|  flex: 1;
   454|  background: none;
   455|  border: none;
   456|  outline: none;
   457|  color: var(--text-primary);
   458|  font-size: 1rem;
   459|  padding: 10px 0;
   460|  font-family: var(--font);
   461|}
   462|.search-bar input::placeholder { color: var(--text-muted); }
   463|.search-reset-btn {
   464|  padding: 8px 18px;
   465|  background: var(--accent);
   466|  color: #fff;
   467|  border: none;
   468|  border-radius: 20px;
   469|  font-size: 0.85rem;
   470|  cursor: pointer;
   471|  font-family: var(--font);
   472|  font-weight: 600;
   473|  transition: background .2s;
   474|}
   475|.search-reset-btn:hover { background: var(--accent-hover); }
   476|
   477|/* ---- Category Hero ---- */
   478|.cat-hero {
   479|  background: linear-gradient(135deg, #111 0%, #1a0a1e 50%, #111 100%);
   480|  padding: 60px 0 40px;
   481|  text-align: center;
   482|  border-bottom: 1px solid var(--border);
   483|}
   484|.cat-hero h1 { font-size: 2.4rem; font-weight: 800; margin-bottom: 10px; }
   485|.cat-hero p { font-size: 1.1rem; color: var(--text-secondary); max-width: 600px; margin: 0 auto; }
   486|
   487|/* ---- Category Pills (Filter) ---- */
   488|.cat-filter-pills {
   489|  display: flex;
   490|  justify-content: center;
   491|  gap: 8px;
   492|  flex-wrap: wrap;
   493|  padding: 20px 0;
   494|}
   495|.cat-pill, .tag-pill {
   496|  display: inline-block;
   497|  padding: 6px 16px;
   498|  border-radius: 20px;
   499|  background: var(--bg-card);
   500|  color: var(--text-secondary);
   501|  font-size: 0.85rem;
   502|  font-weight: 500;
   503|  border: 1px solid var(--border);
   504|  cursor: pointer;
   505|  transition: all .2s;
   506|  text-decoration: none;
   507|  white-space: nowrap;
   508|}
   509|.cat-pill:hover, .tag-pill:hover { border-color: var(--accent); color: var(--text-primary); }
   510|.cat-pill.active {
   511|  background: var(--accent-dim);
   512|  color: var(--accent-hover);
   513|  border-color: var(--accent);
   514|}
   515|.tag-pill.active {
   516|  background: var(--accent-dim);
   517|  color: var(--accent-hover);
   518|  border-color: var(--accent);
   519|}
   520|
   521|/* ---- Tag Cloud ---- */
   522|.tag-cloud {
   523|  display: flex;
   524|  justify-content: center;
   525|  gap: 6px;
   526|  flex-wrap: wrap;
   527|  padding: 0 0 20px;
   528|}
   529|.tag-pill[data-count] { font-size: 0.8rem; }
   530|
   531|/* ---- Result Count ---- */
   532|.result-count {
   533|  display: block;
   534|  text-align: center;
   535|  font-size: 0.9rem;
   536|  color: var(--text-muted);
   537|  padding: 10px 0 0;
   538|}
   539|
   540|/* ---- Pagination ---- */
   541|.pagination {
   542|  display: flex;
   543|  justify-content: center;
   544|  align-items: center;
   545|  gap: 4px;
   546|  padding: 30px 0 50px;
   547|  flex-wrap: wrap;
   548|}
   549|.page-btn {
   550|  display: inline-flex;
   551|  align-items: center;
   552|  justify-content: center;
   553|  min-width: 36px;
   554|  height: 36px;
   555|  padding: 0 10px;
   556|  border-radius: 8px;
   557|  background: var(--bg-card);
   558|  color: var(--text-secondary);
   559|  font-size: 0.9rem;
   560|  font-weight: 500;
   561|  border: 1px solid var(--border);
   562|  cursor: pointer;
   563|  text-decoration: none;
   564|  transition: all .2s;
   565|}
   566|.page-btn:hover { border-color: var(--accent); color: var(--text-primary); }
   567|.page-btn.active { background: var(--accent); color: #fff; border-color: var(--accent); }
   568|.page-btn.prev, .page-btn.next { padding: 0 16px; }
   569|.page-dots { color: var(--text-muted); padding: 0 4px; }
   570|
   571|/* ---- No Results ---- */
   572|.no-results { text-align: center; padding: 60px 20px; color: var(--text-muted); }
   573|.no-results p { font-size: 1.1rem; }
   574|.no-results a { color: var(--accent); }
   575|
   576|/* ---- Related Articles ---- */
   577|.related-heading {
   578|  font-size: 1.5rem;
   579|  margin: 40px 0 20px;
   580|  color: var(--text-primary);
   581|}
   582|.related-grid {
   583|  display: grid;
   584|  grid-template-columns: repeat(auto-fill, minmax(280px, 1fr));
   585|  gap: 20px;
   586|  margin-bottom: 40px;
   587|}
   588|.related-card { border: 1px solid var(--border); }
   589|.related-card:hover { border-color: var(--accent); }
   590|.card-img-link { display: block; text-decoration: none; color: inherit; }
   591|
   592|/* ---- Category Section on Index ---- */
   593|.cat-section {
   594|  padding: 30px 0 20px;
   595|}
   596|.cat-section h2 {
   597|  font-size: 1.6rem;
   598|  margin-bottom: 20px;
   599|  display: flex;
   600|  align-items: center;
   601|  gap: 10px;
   602|}
   603|.cat-section h2 a { color: var(--text-primary); }
   604|.cat-section h2 a:hover { color: var(--accent); }
   605|.cat-more-link {
   606|  display: block;
   607|  text-align: center;
   608|  padding: 16px 0 30px;
   609|  font-size: 1rem;
   610|  font-weight: 600;
   611|}
   612|.cat-more-link a {
   613|  display: inline-block;
   614|  padding: 10px 28px;
   615|  background: var(--accent-dim);
   616|  color: var(--accent-hover);
   617|  border-radius: 20px;
   618|  border: 1px solid rgba(156,39,176,0.3);
   619|  transition: all .2s;
   620|}
   621|.cat-more-link a:hover { background: var(--accent); color: #fff; }
   622|
   623|/* ---- Stat Counter ---- */
   624|.site-stats {
   625|  display: flex;
   626|  justify-content: center;
   627|  gap: 40px;
   628|  padding: 30px 0;
   629|  flex-wrap: wrap;
   630|}
   631|.stat-item { text-align: center; }
   632|.stat-num {
   633|  font-size: 2.2rem;
   634|  font-weight: 800;
   635|  color: var(--accent);
   636|}
   637|.stat-label { font-size: 0.9rem; color: var(--text-muted); margin-top: 4px; }
   638|
   639|/* ---- Mega Footer ---- */
   640|.footer-links-columns {
   641|  display: grid;
   642|  grid-template-columns: repeat(auto-fit, minmax(160px, 1fr));
   643|  gap: 20px;
