  grid-template-columns: repeat(auto-fill, minmax(280px, 1fr));
  gap: 20px;
  margin-bottom: 40px;
}
.related-card { border: 1px solid var(--border); }
.related-card:hover { border-color: var(--accent); }
.card-img-link { display: block; text-decoration: none; color: inherit; }

/* ---- Category Section on Index ---- */
.cat-section {
  padding: 30px 0 20px;
}
.cat-section h2 {
  font-size: 1.6rem;
  margin-bottom: 20px;
  display: flex;
  align-items: center;
  gap: 10px;
}
.cat-section h2 a { color: var(--text-primary); }
.cat-section h2 a:hover { color: var(--accent); }
.cat-more-link {
  display: block;
  text-align: center;
  padding: 16px 0 30px;
  font-size: 1rem;
  font-weight: 600;
}
.cat-more-link a {
  display: inline-block;
  padding: 10px 28px;
  background: var(--accent-dim);
  color: var(--accent-hover);
  border-radius: 20px;
  border: 1px solid rgba(156,39,176,0.3);
  transition: all .2s;
}
.cat-more-link a:hover { background: var(--accent); color: #fff; }

/* ---- Stat Counter ---- */
.site-stats {
  display: flex;
  justify-content: center;
  gap: 40px;
  padding: 30px 0;
  flex-wrap: wrap;
}
.stat-item { text-align: center; }
.stat-num {
  font-size: 2.2rem;
  font-weight: 800;
  color: var(--accent);
}
.stat-label { font-size: 0.9rem; color: var(--text-muted); margin-top: 4px; }

/* ---- Mega Footer ---- */
.footer-links-columns {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(160px, 1fr));
  gap: 20px;
  margin: 20px 0;
}
.footer-links-columns h5 {
  color: var(--text-secondary);
  font-size: 0.85rem;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.5px;
  margin-bottom: 10px;
}
.footer-links-columns a {
  display: block;
  color: var(--text-muted);
  font-size: 0.85rem;
  padding: 3px 0;
}
.footer-links-columns a:hover { color: var(--accent); }

/* ---- Nav Dropdown ---- */
.nav-dropdown { position: relative; }
.nav-dropdown > a::after {
  content: '▾';
  margin-left: 4px;
  font-size: 0.7rem;
  opacity: 0.6;
}
.nav-dropdown-menu {
  display: none;
  position: absolute;
  top: 100%;
  left: 50%;
  transform: translateX(-50%);
  background: var(--bg-secondary);
  border: 1px solid var(--border);
  border-radius: var(--radius-sm);
  padding: 8px 0;
  min-width: 180px;
  z-index: 200;
  box-shadow: var(--shadow);
}
.nav-dropdown-menu a {
  display: block;
  padding: 8px 18px;
  color: var(--text-secondary);
  font-size: 0.9rem;
  white-space: nowrap;
  border-bottom: none !important;
}
.nav-dropdown-menu a:hover { background: var(--bg-hover); color: var(--text-primary); }
.nav-dropdown:hover .nav-dropdown-menu,
.nav-dropdown:focus-within .nav-dropdown-menu { display: block; }

/* ---- Responsive ---- */
@media (max-width: 768px) {
  .cat-hero h1 { font-size: 1.7rem; }
  .site-stats { gap: 20px; }
  .stat-num { font-size: 1.6rem; }
  .related-grid { grid-template-columns: 1fr; }
  .nav-dropdown-menu { left: 0; transform: none; }
  .footer-links-columns { grid-template-columns: 1fr 1fr; }
}

@media (max-width: 480px) {
  .search-bar input { font-size: 0.9rem; }
  .pagination { gap: 2px; }
  .page-btn { min-width: 32px; height: 32px; font-size: 0.8rem; }
  .footer-links-columns { grid-template-columns: 1fr; }
