+  .related-grid { grid-template-columns: 1fr; }
+  .nav-dropdown-menu { left: 0; transform: none; }
+  .footer-links-columns { grid-template-columns: 1fr 1fr; }
+}
+
+@media (max-width: 480px) {
+  .search-bar input { font-size: 0.9rem; }
+  .pagination { gap: 2px; }
+  .page-btn { min-width: 32px; height: 32px; font-size: 0.8rem; }
+  .footer-links-columns { grid-template-columns: 1fr; }
+}
